// ===================================================
// WF-16 Step 1: POST 본문 파싱 + 입력값 검증
// 필수: member_id, title, category, type, difficulty, max_students, price, duration, description
// 선택: schedule_desc, curriculum, image_url, materials, location, contact_instagram, contact_phone, contact_kakao
// ===================================================

const input = $input.first().json;
const body = input.body || input;

function escapeHtml(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/\"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function sanitizeText(str, maxLen) {
  if (!str) return '';
  maxLen = maxLen || 500;
  return String(str)
    .replace(/[\u0000-\b\u000b\f\u000e-\u001f]/g, '')
    .trim()
    .substring(0, maxLen);
}

function sanitizeUrl(url) {
  if (!url) return '';
  const trimmed = String(url).trim();
  if (!trimmed) return '';
  const lower = trimmed.toLowerCase();
  if (lower.startsWith('http://') || lower.startsWith('https://')) {
    return trimmed.substring(0, 2048);
  }
  if (!lower.includes('://') && !lower.includes(':')) {
    return ('https://' + trimmed).substring(0, 2048);
  }
  return '';
}

function extractBrandUid(raw) {
  const text = String(raw || '').replace(/\s+/g, '').trim();
  const match = text.match(/[?&]branduid=([^&#]+)/i);
  if (match && match[1]) return decodeURIComponent(match[1]);
  if (/^[A-Za-z0-9_-]{4,64}$/.test(text)) return text;
  return '';
}

function normalizeKitProductUrl(raw) {
  const text = sanitizeText(raw, 2048);
  if (!text) return '';
  const brandUid = extractBrandUid(text);
  if (brandUid) {
    return '/shop/shopdetail.html?branduid=' + encodeURIComponent(brandUid);
  }
  const lower = text.toLowerCase();
  if (lower.startsWith('http://') || lower.startsWith('https://') || text.indexOf('/shop/') === 0) {
    return text.substring(0, 2048);
  }
  return '';
}

function normalizeDifficulty(raw) {
  const text = sanitizeText(raw, 30);
  const upper = text.toUpperCase();
  const lower = text.toLowerCase();
  if (!text) return '';
  if (upper === 'BEGINNER' || lower === 'beginner' || lower === 'basic' || text.includes('입문') || text.includes('초급')) return 'BEGINNER';
  if (upper === 'INTERMEDIATE' || lower === 'intermediate' || text.includes('중급')) return 'INTERMEDIATE';
  if (upper === 'ADVANCED' || lower === 'advanced' || lower === 'expert' || text.includes('심화') || text.includes('고급')) return 'ADVANCED';
  if (upper === 'ALL_LEVELS' || text.includes('전체')) return 'ALL_LEVELS';
  return upper;
}

function difficultyLabel(code) {
  return { BEGINNER: '입문', INTERMEDIATE: '중급', ADVANCED: '심화', ALL_LEVELS: '전체' }[code] || code;
}

function normalizeRegion(location, classType) {
  const text = sanitizeText(location, 200);
  const type = sanitizeText(classType, 50);
  const upper = text.toUpperCase();
  if (type.includes('온라인') || text.includes('온라인') || upper === 'ONLINE' || upper.includes('ONLINE')) return 'ONLINE';
  if (!text) return '';
  const primary = text.split(' ')[0];
  const map = {
    '서울': 'SEOUL','경기': 'GYEONGGI','경기도': 'GYEONGGI','인천': 'INCHEON','부산': 'BUSAN','대구': 'DAEGU','대전': 'DAEJEON','광주': 'GWANGJU','울산': 'ULSAN','세종': 'SEJONG','강원': 'GANGWON','강원도': 'GANGWON','충북': 'CHUNGBUK','충청북도': 'CHUNGBUK','충남': 'CHUNGNAM','충청남도': 'CHUNGNAM','전북': 'JEONBUK','전라북도': 'JEONBUK','전남': 'JEONNAM','전라남도': 'JEONNAM','경북': 'GYEONGBUK','경상북도': 'GYEONGBUK','경남': 'GYEONGNAM','경상남도': 'GYEONGNAM','제주': 'JEJU','제주도': 'JEJU'
  };
  return map[text] || map[primary] || upper;
}

function buildInvalidResponse(code, message) {
  return [{ json: { _valid: false, _errorResponse: { success: false, error: { code, message }, timestamp: new Date().toISOString() } } }];
}

const memberId = sanitizeText(body.member_id, 100);
const title = sanitizeText(body.title, 100);
const category = sanitizeText(body.category, 50);
const type = sanitizeText(body.type, 50);
const difficulty = normalizeDifficulty(body.difficulty);
const maxStudents = parseInt(body.max_students, 10) || 0;
const price = parseInt(body.price, 10) || 0;
const duration = sanitizeText(body.duration, 50);
const description = sanitizeText(body.description, 2000);
const location = sanitizeText(body.location, 200);
const region = normalizeRegion(location, type);

const missingFields = [];
if (!memberId) missingFields.push('member_id');
if (!title) missingFields.push('title');
if (!category) missingFields.push('category');
if (!type) missingFields.push('type');
if (!difficulty) missingFields.push('difficulty');
if (!maxStudents || maxStudents < 1 || maxStudents > 50) missingFields.push('max_students (1~50)');
if (!price || price < 1000) missingFields.push('price (min 1000)');
if (!duration) missingFields.push('duration');
if (!description) missingFields.push('description');

if (missingFields.length > 0) {
  return buildInvalidResponse('MISSING_PARAMS', missingFields.join(', ') + ' 파라미터가 필요합니다.');
}

const validCategories = ['압화', '레진', '캔들', '석고', '비즈', '기타'];
const validTypes = ['원데이', '정기', '온라인'];
const validDifficulties = ['BEGINNER', 'INTERMEDIATE', 'ADVANCED', 'ALL_LEVELS'];

if (!validCategories.includes(category)) {
  return buildInvalidResponse('INVALID_PARAMS', '유효하지 않은 카테고리입니다: ' + category);
}
if (!validTypes.includes(type)) {
  return buildInvalidResponse('INVALID_PARAMS', '유효하지 않은 강의 형태입니다: ' + type);
}
if (!validDifficulties.includes(difficulty)) {
  return buildInvalidResponse('INVALID_PARAMS', '유효하지 않은 난이도입니다: ' + difficulty);
}

const scheduleDesc = sanitizeText(body.schedule_desc, 1000);
const curriculum = sanitizeText(body.curriculum, 2000);
const imageUrl = sanitizeUrl(body.image_url);
const materials = sanitizeText(body.materials, 1000);
const contactInstagram = sanitizeUrl(body.contact_instagram);
const contactPhone = sanitizeText(body.contact_phone, 20);
const contactKakao = sanitizeUrl(body.contact_kakao);

const schedules = Array.isArray(body.schedules) ? body.schedules.filter((s) => s && s.schedule_date && s.schedule_time).slice(0, 20).map((s) => ({
  schedule_date: sanitizeText(s.schedule_date, 10),
  schedule_time: sanitizeText(s.schedule_time, 5),
  capacity: Math.min(Math.max(parseInt(s.capacity, 10) || 6, 1), 50)
})) : [];

const kitEnabled = Number(body.kit_enabled) === 1 ? 1 : 0;
const kitItems = Array.isArray(body.kit_items) ? body.kit_items.slice(0, 20).map((k) => ({
  name: sanitizeText(k && k.name, 100),
  product_url: normalizeKitProductUrl(k && (k.product_url || k.product_code || '')),
  quantity: Math.min(Math.max(parseInt(k && k.quantity, 10) || 1, 1), 99),
  price: Math.max(parseInt(k && k.price, 10) || 0, 0)
})).filter((k) => k.name || k.product_url) : [];
const kitBundleBrandUid = extractBrandUid(body.kit_bundle_branduid || body.kitBundleBranduid || '');

if (kitEnabled === 1) {
  if (kitItems.length === 0) {
    return buildInvalidResponse('INVALID_PARAMS', '재료키트 자동 배송을 사용하려면 최소 1개 이상의 키트 항목이 필요합니다.');
  }
  for (const item of kitItems) {
    if (!item.name) {
      return buildInvalidResponse('INVALID_PARAMS', '키트 항목명은 비워둘 수 없습니다.');
    }
    if (!item.product_url) {
      return buildInvalidResponse('INVALID_PARAMS', '키트 항목에는 자사몰 상품 링크 또는 branduid가 필요합니다.');
    }
  }
}

return [{
  json: {
    _valid: true,
    memberId,
    title,
    category,
    type,
    difficulty,
    difficultyLabel: difficultyLabel(difficulty),
    region,
    maxStudents,
    price,
    duration,
    description,
    scheduleDesc,
    curriculum,
    imageUrl,
    materials,
    location,
    contactInstagram,
    contactPhone,
    contactKakao,
    schedules,
    kitEnabled,
    kitItems,
    kitBundleBrandUid,
    _safe: {
      title: escapeHtml(title),
      memberId: escapeHtml(memberId),
      category: escapeHtml(category),
      type: escapeHtml(type)
    }
  }
}];

// ===================================================
// WF-16 Step 2: 활성 파트너 확인
// tbl_Partners에 status=active인 파트너가 있어야 강의 등록 가능
// ===================================================

const response = $input.first().json;
const partnerList = response.list || [];
const validData = $('Validate Input').first().json;

if (partnerList.length === 0) {
  return [{
    json: {
      _isPartner: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'NOT_PARTNER',
          message: '활성 파트너만 강의를 등록할 수 있습니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

const partner = partnerList[0];
return [{
  json: {
    _isPartner: true,
    _partnerCode: partner.partner_code || '',
    _partnerName: partner.partner_name || partner.applicant_name || validData.memberId,
    ...validData
  }
}];

// ===================================================
// WF-16 Step 3: class_id 생성 (CL_YYYYMM_XXX)
// ===================================================

const prevData = $input.first().json;
const now = new Date();

// === class_id 생성: CL_YYYYMM_XXX ===
const pad = (n) => String(n).padStart(2, '0');
const monthStr = String(now.getFullYear()).substring(2) + pad(now.getMonth() + 1);
const randomSuffix = String(Math.floor(100 + Math.random() * 900));
const classId = 'CL_' + now.getFullYear() + pad(now.getMonth() + 1) + '_' + randomSuffix;

const createdDate = now.toISOString();

return [{
  json: {
    ...prevData,
    _classId: classId,
    _createdDate: createdDate
  }
}];

// ===================================================
// WF-16 Step 4: NocoDB 레코드 생성 결과 확인
// ===================================================

const createResult = $input.first().json;
const prevData = $('Generate Class ID').first().json;

const recordCreated = !!createResult.Id || !!createResult.id;

if (!recordCreated) {
  return [{
    json: {
      _success: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'CLASS_CREATE_FAILED',
          message: '강의 등록 저장에 실패했습니다. 잠시 후 다시 시도해 주세요.'
        },
        timestamp: new Date().toISOString()
      },
      _telegramError: '강의 등록 저장 실패: ' + prevData.title + ' by ' + prevData._partnerName + ' (' + prevData.memberId + ')'
    }
  }];
}

return [{
  json: {
    _success: true,
    ...prevData,
    _nocodbRecordId: createResult.Id || createResult.id
  }
}];

// ===================================================
// WF-16 Step 5a: 텔레그램 관리자 알림 메시지 구성
// ===================================================

const data = $input.first().json;
const priceFormatted = Number(data.price).toLocaleString('ko-KR');
const lines = [
  '[강의 등록 신청] 새 강의가 등록되었습니다',
  '',
  '강의명: ' + data.title,
  '파트너: ' + data._partnerName + ' (' + data._partnerCode + ')',
  '카테고리: ' + data.category,
  '형태: ' + data.type,
  '난이도: ' + (data.difficultyLabel || data.difficulty),
  '지역코드: ' + (data.region || '-'),
  '수강료: ' + priceFormatted + '원',
  '최대 인원: ' + data.maxStudents + '명',
  '소요시간: ' + data.duration,
  '강의 ID: ' + data._classId
];

if (data.location) {
  lines.push('장소: ' + data.location);
}

lines.push('');
lines.push('-> NocoDB tbl_Classes에서 검토 후 status를 ACTIVE로 변경해주세요.');

return [{
  json: {
    ...data,
    _telegramMessage: lines.join('\n')
  }
}];

// ===================================================
// WF-16 Step 5b: 성공 응답 구성
// ===================================================

const data = $('Check Create Result').first().json;

return [{
  json: {
    success: true,
    data: {
      class_id: data._classId,
      status: 'PENDING_REVIEW',
      message: '강의 등록이 접수되었습니다. 관리자 검수 후 플랫폼에 노출됩니다.'
    },
    timestamp: new Date().toISOString()
  }
}];

// ===================================================
// WF-16: 레코드 생성 실패 시 에러 텔레그램 알림
// ===================================================

const data = $input.first().json;

const message = '[강의 등록 실패] 저장 오류\n\n'
  + (data._telegramError || '알 수 없는 오류');

return [{
  json: {
    ...data,
    _errorTelegramMessage: message
  }
}];

// ===================================================
// WF-16 Step 5c: tbl_Schedules 초기 일정 저장
// 프론트에서 전송된 schedules[] 배열을 tbl_Schedules에 저장
// ===================================================

const https = require('https');
const data = $input.first().json;
const schedules = data.schedules || [];

if (schedules.length === 0) {
  return [{ json: { _schedulesCreated: 0 } }];
}

function nocoRequest(method, path, body) {
  return new Promise((resolve, reject) => {
    const options = {
      hostname: 'nocodb.pressco21.com',
      path: '/api/v1/db/data/noco/' + $env.NOCODB_PROJECT_ID + path,
      method: method,
      headers: {
        'xc-token': $env.NOCODB_API_TOKEN,
        'Content-Type': 'application/json'
      }
    };
    const req = https.request(options, (res) => {
      let d = '';
      res.on('data', c => d += c);
      res.on('end', () => {
        try { resolve(JSON.parse(d)); } catch(e) { resolve(d); }
      });
    });
    req.on('error', reject);
    if (body) req.write(JSON.stringify(body));
    req.end();
  });
}

const classId = data._classId;
const pad = (n) => String(n).padStart(2, '0');
let created = 0;

for (const s of schedules) {
  try {
    const dateStr = (s.schedule_date || '').replace(/-/g, '');
    const rand = String(Math.floor(100000 + Math.random() * 900000));
    const scheduleId = 'SCH_' + dateStr + '_' + rand;

    await nocoRequest('POST', '/mschd3d81ad88fb', {
      schedule_id: scheduleId,
      class_id: classId,
      schedule_date: s.schedule_date,
      schedule_time: s.schedule_time,
      capacity: s.capacity || 6,
      booked_count: 0,
      status: 'active'
    });
    created++;
  } catch(e) {
    // 개별 일정 저장 실패해도 나머지 계속 진행
  }
}

return [{ json: { _schedulesCreated: created } }];
